public static EtgSalesInvoiceController construct()
{
    return new EtgSalesInvoiceController();

}

public static void main(Args _args)

{

    EtgSalesInvoiceController controller = new EtgSalesInvoiceController();

    controller.parmArgs(_args);

    controller.parmReportName(ssrsReportStr(ETGSalesInvoice, ETGReport));

    controller.parmShowDialog(false);

    controller.parmDialogCaption("Show Invoice");

    controller.startOperation();

}
